alue='胸痛'>💔 胸痛</label><label class='chk-item' onclick='this.classList.toggle(\"checked\")'><input type='checkbox' value='頭暈'>😵 頭暈</label><label class='chk-item' onclick='this.classList.toggle(\"checked\")'><input type='checkbox' value='失眠'>😴 失眠</label><label class='chk-item' onclick='this.classList.toggle(\"checked\")'><input type='checkbox' value='食慾不振'>🍽️ 食慾不振</label></div></div><div class='card'><h2>✍️ 補充描述（選填）</h2><div class='form-group'><textarea id='symptomText' placeholder='例如：我從昨天開始頭痛、喉嚨有點痛，今天開始有點發燒，體溫約38度，沒有咳嗽...'></textarea></div><div class='alert alert-info'>💡 本系統提供初步參考建議，不能取代專業醫療診斷。如症狀嚴重請立即就醫。</div><button class='btn btn-primary btn-block' id='submitBtn' onclick='submitSymptoms()'>🔍 開始 AI 分析</button></div><div id='loadingArea' style='display:none'><div class='card' style='text-align:center;padding:2rem'><div class='spinner'></div><p style='color:var(--p);font-weight:600'>AI 正在分析您的症狀...</p></div></div></main><script>function submitSymptoms(){  var txt=document.getElementById('symptomText').value.trim();  var chks=Array.from(document.querySelectorAll('#chkGrid input:checked')).map(function(c){return c.value});  if(!txt&&chks.length===0){alert('請至少勾選一項症狀或輸入描述');return;}  document.getElementById('submitBtn').disabled=true;  document.getElementById('loadingArea').style.display='block';  fetch('/api/classify',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({symptoms:txt,checkboxes:chks})})  .then(function(r){return r.json()})  .then(function(d){    if(d._apiError){      document.getElementById('loadingArea').style.display='none';      document.getElementById('submitBtn').disabled=false;      var e=document.getElementById('apiErrBox');      if(!e){e=document.createElement('div');e.id='apiErrBox';e.className='alert alert-warning';document.querySelector('main').appendChild(e);}      e.style.display='';e.innerText='⚠️ '+d._apiErrorMsg;      return Promise.reject('api_error');    }    var ob=d._origBody||{};    var dt=(ob.symptoms||'').slice(0,60)||(Array.isArray(ob.checkboxes)?ob.checkboxes.join('、'):'')||'（無輸入）';    var sd={displayText:dt,category:d.category,severity:d.severity,recommendation:d.recommendation,department:d.department,advice:d.advice};    return fetch('/api/save-assess',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(sd)}).then(function(){return d;});  })  .then(function(d){    var meds=(d._dbMeds&&d._dbMeds.length>0)?d._dbMeds:(d.medicines||[]);    var p=new URLSearchParams({category:d.category||'',severity:d.severity||'',recommendation:d.recommendation||'',department:d.department||'',advice:d.advice||'',warning:d.warning||'',medicines:JSON.stringify(meds)});    window.location='/triage?'+p.toString();  })  .catch(function(e){    if(e==='api_error') return;    alert('分析失敗，請稍後再試：'+e.message);    document.getElementById('submitBtn').disabled=false;    document.getElementById('loadingArea').style.display='none';  });}</script></body></html>";
