  "<script>",
  // 自動定位：取得座標後填入 hidden input + 自動 submit（若未帶座標）
  "var _autoSubmitted = false;",
  "function autoLocate(){",
  "  if(!navigator.geolocation) return;",
  "  navigator.geolocation.getCurrentPosition(function(pos){",
  "    var lat=pos.coords.latitude, lng=pos.coords.longitude;",
  "    document.getElementById('hLat').value=lat;",
  "    document.getElementById('hLng').value=lng;",
  // 若還沒有縣市，用 Nominatim 反查
  "    if(!document.getElementById('countySelect').value){",
  "      fetch('https://nominatim.openstreetmap.org/reverse?format=json&lat='+lat+'&lon='+lng,{headers:{'Accept-Language':'zh-TW'}})",
  "      .then(function(r){return r.json();})",
  "      .then(function(d){",
  "        var city=d.address&&(d.address.city||d.address.county||'');",
  "        var codeMap={'台北市':'63000','臺北市':'63000','新北市':'65000','桃園市':'68000','台中市':'66000','臺中市':'66000','台南市':'67000','臺南市':'67000','高雄市':'64000','宜蘭縣':'10002','新竹縣':'10004','苗栗縣':'10005','彰化縣':'10007','南投縣':'10008','雲林縣':'10009','嘉義縣':'10010','屏東縣':'10013','台東縣':'10014','臺東縣':'10014','花蓮縣':'10015','澎湖縣':'10016','基隆市':'10017','新竹市':'10018','嘉義市':'10020','連江縣':'09007','金門縣':'09020'};",
  "        var code=codeMap[city];",
  "        if(code&&!_autoSubmitted){ _autoSubmitted=true; document.getElementById('countySelect').value=code; document.getElementById('clinicForm').submit(); }",
  "      }).catch(function(){});",
  "    } else if(!_autoSubmitted) {",
  // 已有縣市但沒座標，重新送出帶座標的請求
  "      _autoSubmitted=true; document.getElementById('clinicForm').submit();",
  "    }",
  "  },function(){},{ timeout:8000 });",
  "}",
  // 只在沒有座標時自動定位
  ((!userLat) ? "autoLocate();" : ""),
