].join('');

msg.payload    = html;
msg.statusCode = 200;
msg.headers    = {'Content-Type':'text/html; charset=utf-8'};
return msg;

msg._sqlIndex = (msg._sqlIndex || 0) + 1;
var sqls = msg._sqls || [];

if(msg._sqlIndex < sqls.length) {
  node.warn('[upsert] 送出第 '+(msg._sqlIndex+1)+'/'+sqls.length+' 批');
  msg.payload = sqls[msg._sqlIndex];
  delete msg.params;
  return [msg, null]; // 繼續送 MSSQL
}
// 全部批次完成
node.warn('[upsert] 全部批次完成');
return [null, msg]; // 進入 sync_next

msg.payload = "SELECT id, address FROM clinics WHERE lat IS NULL AND address IS NOT NULL AND LTRIM(RTRIM(address)) != '' ORDER BY id";
delete msg.params;
return msg;

var rows = msg.payload;
if(rows && rows.recordset) rows = rows.recordset;
if(!Array.isArray(rows)) rows = [];

if(rows.length === 0) {
  node.warn('[geocode] 所有診所已完成 Geocoding，無待處理資料');
  return;
}
node.warn('[geocode] 開始處理全部 '+rows.length+' 筆，預計約 '+(Math.ceil(rows.length*1.1/60))+' 分鐘');
msg._rows  = rows;
msg._idx   = 0;
msg._done  = 0;
msg._fail  = 0;
return msg;

var rows = msg._rows;
var idx  = msg._idx;

if (idx >= rows.length) {
  node.warn('[geocode] ✅ 完成！成功: '+(msg._done||0)+' 失敗: '+(msg._fail||0));
  return null;
}
if (idx % 100 === 0)
  node.warn('[geocode] 進度 '+idx+'/'+rows.length+' ('+Math.round(idx/rows.length*100)+'%)');

var r     = rows[idx];
var stage = msg._stage || 0;

function cleanAddr(raw) {
  var s = (raw || '').trim();
  s = s.replace(/[０-９]/g, function(c){ return String.fromCharCode(c.charCodeAt(0)-0xFEE0); });
  s = s.replace(/[Ａ-Ｚａ-ｚ]/g, function(c){ return String.fromCharCode(c.charCodeAt(0)-0xFEE0); });
  s = s.replace(/　/g, '').replace(/[－ー‐−]/g, '-');
  s = s.replace(/臺/g, '台');
  var cnMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
  s = s.replace(/[一二三四五六七八九十]+段/g, function(m){
    return (cnMap[m[0]] || m[0]) + '段';
  });
  s = s.split(/[、；,]/)[0];
  s = s.replace(/[（(][^）)]*[）)]/g, '');
  s = s.replace(/\d+[樓FfBb層][^\d]*$/i, '');
  s = s.replace(/地[下]?\d+[樓F]/gi, '');
  s = s.replace(/號\d+$/, '號');
  s = s.replace(/(\d+)之\d+(號)/, '$1$2');
  return s.trim();
}

var addr = cleanAddr(r.address);
msg._currentRow  = r;
msg._currentAddr = addr;
msg.method  = 'GET';
msg.payload = '';

// ── Stage 0：Nominatim 結構化查詢（縣市區 + 路號分離）──
if (stage === 0) {
  var cityMatch  = addr.match(/^(.{2,4}[縣市])(.{2,4}[鄉鎮市區])/);
  var city       = cityMatch ? (cityMatch[1]+cityMatch[2]) : '';
  var streetPart = cityMatch ? addr.slice(cityMatch[0].length) : addr;
  node.warn('[geocode] Nominatim-結構 ('+idx+'): city='+city+' street='+streetPart);
  msg.url = 'https://nominatim.openstreetmap.org/search'
    + '?street=' + encodeURIComponent(streetPart)
    + '&city='   + encodeURIComponent(city)
    + '&country=TW&format=json&limit=1&accept-language=zh-TW';
  msg.headers = {
    'User-Agent': 'MediMatch/1.0 (non-commercial)',
    'Accept': 'application/json'
  };
  msg._stage = 0;
  return msg;
}

// ── Stage 1：Nominatim 移除門牌，只搜路名 ──
if (stage === 1) {
  var noNum = addr.replace(/\d+號.*$/, '').replace(/\d+之\d+$/, '').trim();
  node.warn('[geocode] Nominatim-路名 ('+idx+'): '+noNum);
  msg.url = 'https://nominatim.openstreetmap.org/search?q='
    + encodeURIComponent(noNum + ' Taiwan')
    + '&format=json&limit=1&countrycodes=tw&accept-language=zh-TW';
  msg.headers = {
    'User-Agent': 'MediMatch/1.0 (non-commercial)',
    'Accept': 'application/json'
  };
  msg._stage = 1;
  return msg;
}

// ── Stage 2：Nominatim 只到鄉鎮區 ──
if (stage === 2) {
  var distOnly = (addr.match(/^.{2,4}[縣市].{2,4}[鄉鎮市區]/) || [addr.slice(0,9)])[0];
  node.warn('[geocode] Nominatim-鄉鎮 ('+idx+'): '+distOnly);
  msg.url = 'https://nominatim.openstreetmap.org/search?q='
    + encodeURIComponent(distOnly + ' Taiwan')
    + '&format=json&limit=1&countrycodes=tw&accept-language=zh-TW';
  msg.headers = {
    'User-Agent': 'MediMatch/1.0 (non-commercial)',
    'Accept': 'application/json'
  };
  msg._stage = 2;
  return msg;
}

// ── 全部失敗 ──
node.warn('[geocode] ✗ 放棄: '+addr);
msg._fail  = (msg._fail||0) + 1;
msg._stage = 0;
msg._retry = 0;
msg._idx++;
msg.payload = 'UPDATE clinics SET lat=0,lng=0,geocode_quality=N\'failed\' WHERE id='+r.id;
delete msg.params;
return msg;

var r     = msg._currentRow;
var addr  = msg._currentAddr;
var stage = msg._stage || 0;
var raw   = msg.payload;

// ── HTTP 429 處理 ──
var httpStatus = msg.statusCode || 200;
if (httpStatus === 429) {
  msg._retry = (msg._retry||0) + 1;
  node.warn('[geocode] 429 #'+msg._retry+' stage'+stage+': '+addr);
  if (msg._retry >= 3) {
    msg._retry = 0;
    if (stage < 2) {
      msg._stage = stage + 1;
      msg.payload = 'SELECT 1 AS ok';
      delete msg.params;
      return [msg, null]; // 經過 delay 再試下一 stage
    }
    node.warn('[geocode] ✗ rate limit 放棄: '+addr);
    msg._fail = (msg._fail||0)+1;
    msg._stage = 0; msg._retry = 0; msg._idx++;
    msg.payload = 'UPDATE clinics SET lat=0,lng=0,geocode_quality=N\'failed\' WHERE id='+r.id;
    delete msg.params;
    return [msg, null];
  }
  // 還有重試機會，等待後重試同一 stage
  msg.payload = 'SELECT 1 AS ok';
  delete msg.params;
  return [msg, null];
}
msg._retry = 0;

// ── 解析 payload ──
var rawStr = (typeof raw === 'string') ? raw.trim() : '';
var data   = null;

if (rawStr.charAt(0) === '<') {
  // XML = Nominatim 錯誤頁（rate limit）
  node.warn('[geocode] 收到 XML，視為 rate limit: '+addr);
  msg._retry = (msg._retry||0) + 1;
  msg.payload = 'SELECT 1 AS ok';
  delete msg.params;
  return [msg, null];
} else if (rawStr) {
  if (typeof raw === 'object' && raw !== null) {
    data = raw;
  } else {
    try { data = JSON.parse(rawStr); } catch(e) {
      node.warn('[geocode] JSON parse 失敗 stage'+stage+': '+rawStr.slice(0,80));
    }
  }
}

var lat = null, lng = null;

// ── 解析 Nominatim 格式 ──
if (data && Array.isArray(data) && data.length > 0) {
  lat = parseFloat(data[0].lat);
  lng = parseFloat(data[0].lon);
}

// ── 台灣座標範圍驗證 ──
if (lat !== null && lng !== null && !isNaN(lat) && !isNaN(lng)) {
  if (lat < 21.5 || lat > 25.5 || lng < 119.5 || lng > 122.2) {
    node.warn('[geocode] 座標不在台灣: '+lat+','+lng+' | '+addr);
    lat = null; lng = null;
  }
}

// ── 精度檢查 ──
var quality = 'ok';
if (lat !== null && lng !== null) {
  var latDec = (lat.toString().split('.')[1]||'').length;
  var lngDec = (lng.toString().split('.')[1]||'').length;
  if (latDec < 3 || lngDec < 3) quality = 'low';
}

// ── 成功 ──
if (lat !== null && lng !== null) {
  var srcMap = {0:'Nominatim-結構', 1:'Nominatim-路名', 2:'Nominatim-鄉鎮區'};
  node.warn('[geocode] ✓ ['+srcMap[stage]+'] '+addr
    +' → '+Math.round(lat*10000)/10000
    +','+Math.round(lng*10000)/10000
    +(quality==='low'?' ⚠️低精度':''));
  msg._done  = (msg._done||0)+1;
  msg._stage = 0; msg._retry = 0; msg._idx++;
  msg.payload = 'UPDATE clinics SET lat='+lat+',lng='+lng
    +',geocode_quality=N\''+quality+'\' WHERE id='+r.id;
  delete msg.params;
  return [msg, null]; // output1 → geo_update → geo_delay → 下一筆
}

// ── 失敗，試下一 stage ──
if (stage < 2) {
  node.warn('[geocode] stage'+stage+' 無結果，試 stage'+(stage+1)+': '+addr);
  msg._stage = stage + 1;
  msg._retry = 0;
  msg.payload = 'SELECT 1 AS ok';
  delete msg.params;
  return [msg, null]; // output1 → geo_delay → 下一 stage
}

// ── 全部放棄 ──
node.warn('[geocode] ✗ 全部放棄: '+addr);
msg._fail  = (msg._fail||0)+1;
msg._stage = 0; msg._retry = 0; msg._idx++;
msg.payload = 'UPDATE clinics SET lat=0,lng=0,geocode_quality=N\'failed\' WHERE id='+r.id;
delete msg.params;
return [msg, null]; // output1 → geo_update → geo_delay → 下一筆

var county = (msg.req.query.county || '').replace(/'/g, "''");
var dept   = (msg.req.query.dept   || '').replace(/'/g, "''");
var where  = ["LTRIM(RTRIM(contract_type)) IN ('1','2','3','4')"];
if(county) where.push("LTRIM(RTRIM(county_code)) = N'" + county + "'");
if(dept)   where.push("departments LIKE N'%" + dept + "%'");
msg.payload = "SELECT TOP 100 med_name FROM clinics WHERE " + where.join(" AND ") + " ORDER BY med_name";
delete msg.params;
return msg;

var rows = msg.payload;
if(rows && rows.recordset) rows = rows.recordset;
if(!Array.isArray(rows)) rows = [];
msg.payload    = { success: true, data: rows };
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;
